import sys

class Solution:
    def solve(self, n: int, i: int) -> str:
        return 'YES' if (n & (1 << i)) else 'NO'

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        i = int(next(it))
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.solve(n, i)
    print(ans)

solutions.cpp:
#include <numeric>

#include <iostream>
#include <string>

using namespace std;

class Solution {
public:
    string solve(int n, int i) {
        return (n & (1 << i)) ? "YES" : "NO";
    }
};

int main() {
    int n, i;
    if (!(cin >> n >> i)) return 0;
    Solution sol;
    string ans = sol.solve(n, i);
    cout << ans << endl;
    return 0;
}
